FUNCTION Evaluate(expr, values):
 // expr is in postfix/prefix notation
 // values is dictionary: {'P': True, 'Q': False}

 IF expr is atomic proposition:
 RETURN values[expr]

 IF expr is NOT P:
 RETURN NOT Evaluate(P, values)

 IF expr is P AND Q:
 RETURN Evaluate(P, values) AND Evaluate(Q, values)

 IF expr is P OR Q:
 RETURN Evaluate(P, values) OR Evaluate(Q, values)

 IF expr is P IMPLY Q:
 // False only when P=True and Q=False
 RETURN (NOT Evaluate(P, values)) OR Evaluate(Q, values)

 RETURN

// To check tautology: Evaluate for ALL combinations
// If all results are True, it's a tautology

FUNCTION CheckEquivalence(expr1, expr2, variables):
 numVars = LENGTH(variables)
 numRows = 2^numVars

 FOR i FROM 0 TO numRows-1:
 // Create truth value assignment
 values = {}
 FOR j FROM 0 TO numVars-1:
 values[variables[j]] = (i // (2^j)) % 2 == 1

 // Evaluate both expressions
 result1 = Evaluate(expr1, values)
 result2 = Evaluate(expr2, values)

 // If any row differs, not equivalent
 IF result1 != result2:
 RETURN FALSE // Not equivalent

 RETURN TRUE // Logically equivalent

